function levelOrder(root: TreeNode | null): number[][] {
  if (!root) return [];
  const out: number[][] = [], q: TreeNode[] = [root];
  while (q.length) {
    const lvl: number[] = [], n = q.length;
    for (let i = 0; i < n; i++) {
      const x = q.shift()!;
      lvl.push(x.val);
      if (x.left) q.push(x.left);
      if (x.right) q.push(x.right);
    }
    out.push(lvl);
  }
  return out;
}
